        return entry.ip in allowed
    return pred


def date_range_filter(since: datetime | None, until: datetime | None) -> Callable[[LogEntry], bool]:
    """Match entries whose timestamp is within [since, until], either side optional."""
    def pred(entry: LogEntry) -> bool:
        if since is not None and entry.timestamp < since:
            return False
        if until is not None and entry.timestamp > until:
            return False
        return True
    return pred


def expression_filter(expr: str) -> Callable[[LogEntry], bool]:
    """Filter by a Python expression where `entry` is the LogEntry.

    Uses ast.parse to validate the expression is safe (only attribute access,
    comparisons, arithmetic, and boolean operations on `entry`).

    Examples:
        "entry.status >= 500"
        "entry.bytes > 1024 and entry.method == 'GET'"
    """
    # Validate expression is safe: only allow attribute access on 'entry',
    # comparisons, arithmetic, boolean ops, and literals.
    try:
        tree = ast.parse(expr, mode="eval")
    except SyntaxError as e:
        raise ValueError(f"invalid expression: {e}") from e

    _validate_expr_node(tree.body)

    compiled = compile(expr, "<expression_filter>", "eval")

    def pred(entry: LogEntry) -> bool:
        return bool(eval(compiled, {"__builtins__": {}}, {"entry": entry}))
    return pred


def _validate_expr_node(node: ast.AST) -> None:
    """Recursively validate that an AST node only contains safe operations.

    Raises ValueError if the node contains unsafe constructs like function calls,
    attribute access on anything other than 'entry', or arbitrary name access.
    """
    if isinstance(node, ast.Expression):
        _validate_expr_node(node.body)
    elif isinstance(node, ast.Compare):
        _validate_expr_node(node.left)
        for op in node.ops:
            _validate_expr_node(op)
        for comp in node.comparators:
            _validate_expr_node(comp)
    elif isinstance(node, ast.BoolOp):
        _validate_expr_node(node.op)
        for val in node.values:
            _validate_expr_node(val)
    elif isinstance(node, ast.UnaryOp):
        _validate_expr_node(node.op)
        _validate_expr_node(node.operand)
    elif isinstance(node, ast.BinOp):
        _validate_expr_node(node.op)
        _validate_expr_node(node.left)
        _validate_expr_node(node.right)
    elif isinstance(node, ast.Attribute):
        # Only allow attribute access on 'entry' (e.g. entry.status)
        if isinstance(node.value, ast.Name) and node.value.id == "entry":
            return
        raise ValueError(
            f"attribute access only allowed on 'entry', got: {ast.dump(node)}"
        )
    elif isinstance(node, ast.Name):
        # Only allow the name 'entry'
        if node.id == "entry":
            return
        raise ValueError(
            f"only 'entry' is allowed as a variable name, got: {node.id}"
        )
    elif isinstance(node, (ast.Constant,)):
        # Literals are always safe
        return
    elif isinstance(node, (
        ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE,
        ast.And, ast.Or,
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod,
        ast.Not, ast.USub, ast.UAdd,
    )):
        # Operators are always safe
        return
    else:
        raise ValueError(
            f"unsafe expression node type: {type(node).__name__}"
        )

